<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    width: 100vw; height: 100vh; overflow: hidden;
    font-family: 'Ubuntu', 'Segoe UI', sans-serif;
    background: #1a1a2e;
    user-select: none;
  }

  #desktop {
    position: relative;
    width: 100vw; height: 100vh;
    background:
      radial-gradient(ellipse at 20% 50%, rgba(120,40,200,0.3) 0%, transparent 60%),
      radial-gradient(ellipse at 80% 20%, rgba(40,80,200,0.25) 0%, transparent 50%),
      radial-gradient(ellipse at 60% 80%, rgba(200,60,120,0.2) 0%, transparent 50%),
      linear-gradient(135deg, #0d0d1a 0%, #1a0a2e 40%, #0a1628 100%);
    overflow: hidden;
  }

  /* Subtle grid overlay */
  #desktop::before {
    content: '';
    position: absolute; inset: 0;
    background-image:
      linear-gradient(rgba(255,255,255,0.015) 1px, transparent 1px),
      linear-gradient(90deg, rgba(255,255,255,0.015) 1px, transparent 1px);
    background-size: 40px 40px;
    pointer-events: none;
  }

  /* Top bar */
  #topbar {
    position: absolute; top: 0; left: 0; right: 0; height: 28px;
    background: rgba(15,15,25,0.92);
    backdrop-filter: blur(8px);
    border-bottom: 1px solid rgba(255,255,255,0.08);
    display: flex; align-items: center; justify-content: space-between;
    padding: 0 12px; z-index: 1000; color: rgba(255,255,255,0.85);
    font-size: 12px; font-weight: 500;
  }
  #topbar-left { display: flex; align-items: center; gap: 16px; }
  #topbar-right { display: flex; align-items: center; gap: 12px; }
  .topbar-dot { width: 6px; height: 6px; border-radius: 50%; background: #e95420; }
  #topbar-time { font-size: 12px; color: rgba(255,255,255,0.8); }

  /* Taskbar/Dock */
  #taskbar {
    position: absolute; bottom: 12px; left: 50%; transform: translateX(-50%);
    background: rgba(15,15,25,0.88);
    backdrop-filter: blur(16px);
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 16px;
    padding: 8px 16px;
    display: flex; align-items: center; gap: 10px;
    z-index: 1000;
    box-shadow: 0 8px 32px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,255,255,0.05) inset;
  }

  .dock-btn {
    width: 52px; height: 52px; border-radius: 12px;
    border: none; cursor: pointer;
    display: flex; flex-direction: column; align-items: center; justify-content: center;
    gap: 3px; font-size: 10px; font-weight: 500;
    transition: transform 0.15s ease, box-shadow 0.15s ease;
    position: relative;
  }
  .dock-btn:hover { transform: translateY(-6px) scale(1.08); }
  .dock-btn:active { transform: translateY(-3px) scale(1.04); }
  .dock-btn svg { width: 28px; height: 28px; }

  #open-files {
    background: linear-gradient(135deg, #2d7dd2, #1a5fa8);
    color: rgba(255,255,255,0.9);
    box-shadow: 0 4px 16px rgba(45,125,210,0.4);
  }
  #open-notepad {
    background: linear-gradient(135deg, #e8a020, #c07010);
    color: rgba(255,255,255,0.9);
    box-shadow: 0 4px 16px rgba(232,160,32,0.4);
  }

  /* Windows */
  .window {
    position: absolute;
    min-width: 360px; min-height: 240px;
    background: #1e1e2e;
    border: 1px solid rgba(255,255,255,0.12);
    border-radius: 10px;
    box-shadow: 0 20px 60px rgba(0,0,0,0.7), 0 0 0 1px rgba(255,255,255,0.04) inset;
    display: flex; flex-direction: column;
    z-index: 100;
    overflow: hidden;
    resize: both;
  }
  .window.hidden { display: none !important; }

  .win-titlebar {
    height: 36px; min-height: 36px;
    background: linear-gradient(180deg, #2a2a3e, #252535);
    border-bottom: 1px solid rgba(255,255,255,0.08);
    display: flex; align-items: center; padding: 0 12px;
    gap: 8px; cursor: move; flex-shrink: 0;
  }
  .win-dots { display: flex; gap: 6px; }
  .win-dot {
    width: 12px; height: 12px; border-radius: 50%;
    border: 1px solid rgba(0,0,0,0.2);
    cursor: pointer; transition: filter 0.1s;
  }
  .win-dot:hover { filter: brightness(1.3); }
  .win-dot.red { background: #ff5f57; }
  .win-dot.yellow { background: #febc2e; }
  .win-dot.green { background: #28c840; }
  .win-close { background: #ff5f57; border: 1px solid rgba(0,0,0,0.2); }
  .win-title {
    flex: 1; text-align: center; font-size: 13px; font-weight: 500;
    color: rgba(255,255,255,0.7); pointer-events: none;
  }
  .win-body { flex: 1; overflow: hidden; display: flex; flex-direction: column; }

  /* Files Window */
  #files-window { width: 600px; height: 420px; top: 80px; left: 80px; }

  #files-toolbar {
    height: 40px; min-height: 40px;
    background: #252535;
    border-bottom: 1px solid rgba(255,255,255,0.06);
    display: flex; align-items: center; padding: 0 10px; gap: 8px; flex-shrink: 0;
  }
  #files-up {
    width: 28px; height: 28px; border-radius: 6px;
    background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.1);
    color: rgba(255,255,255,0.7); cursor: pointer; font-size: 14px;
    display: flex; align-items: center; justify-content: center;
    transition: background 0.1s;
  }
  #files-up:hover { background: rgba(255,255,255,0.12); }
  #files-path {
    flex: 1; background: rgba(0,0,0,0.3);
    border: 1px solid rgba(255,255,255,0.1); border-radius: 6px;
    color: rgba(255,255,255,0.85); font-size: 13px; padding: 4px 10px;
    font-family: 'Ubuntu Mono', monospace;
  }

  #files-content {
    flex: 1; overflow-y: auto; padding: 12px;
    display: flex; flex-wrap: wrap; align-content: flex-start; gap: 8px;
  }
  #files-content::-webkit-scrollbar { width: 6px; }
  #files-content::-webkit-scrollbar-track { background: transparent; }
  #files-content::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.15); border-radius: 3px; }

  .fs-item {
    width: 80px; height: 80px; border-radius: 8px;
    display: flex; flex-direction: column; align-items: center; justify-content: center;
    gap: 4px; cursor: pointer; padding: 8px 4px;
    transition: background 0.12s;
    color: rgba(255,255,255,0.85); font-size: 11px; text-align: center;
    word-break: break-all;
  }
  .fs-item:hover { background: rgba(255,255,255,0.07); }
  .fs-item.selected { background: rgba(45,125,210,0.3); }
  .fs-item svg { width: 36px; height: 36px; flex-shrink: 0; }

  /* Notepad Window */
  #notepad-window { width: 620px; height: 460px; top: 100px; left: 200px; }

  #tabs-bar {
    background: #252535;
    border-bottom: 1px solid rgba(255,255,255,0.06);
    display: flex; align-items: stretch; flex-shrink: 0;
    min-height: 36px; overflow-x: auto;
  }
  #tabs-bar::-webkit-scrollbar { height: 3px; }
  #tabs-bar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.15); }

  #tabs { display: flex; align-items: stretch; flex: 1; }

  .tab {
    padding: 0 14px; min-width: 100px; max-width: 160px;
    display: flex; align-items: center; justify-content: space-between; gap: 6px;
    font-size: 12px; color: rgba(255,255,255,0.5); cursor: pointer;
    border-right: 1px solid rgba(255,255,255,0.06);
    transition: background 0.1s, color 0.1s;
    white-space: nowrap; overflow: hidden;
    position: relative;
  }
  .tab:hover { background: rgba(255,255,255,0.05); color: rgba(255,255,255,0.75); }
  .tab.active {
    background: #1e1e2e; color: rgba(255,255,255,0.9);
    border-bottom: 2px solid #e95420;
  }
  .tab-name { flex: 1; overflow: hidden; text-overflow: ellipsis; }
  .tab-close {
    width: 16px; height: 16px; border-radius: 50%; border: none;
    background: transparent; color: rgba(255,255,255,0.4); cursor: pointer;
    font-size: 12px; line-height: 1; display: flex; align-items: center; justify-content: center;
    flex-shrink: 0; transition: background 0.1s, color 0.1s;
  }
  .tab-close:hover { background: rgba(255,0,0,0.3); color: #fff; }

  #new-tab {
    width: 32px; min-width: 32px; border: none; background: transparent;
    color: rgba(255,255,255,0.5); font-size: 18px; cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    transition: color 0.1s, background 0.1s;
    flex-shrink: 0;
  }
  #new-tab:hover { color: #fff; background: rgba(255,255,255,0.06); }

  #editor {
    flex: 1; background: #1e1e2e; border: none; outline: none; resize: none;
    color: rgba(255,255,255,0.85); font-family: 'Ubuntu Mono', 'Courier New', monospace;
    font-size: 13px; line-height: 1.6; padding: 12px 16px;
    caret-color: #e95420;
  }
  #editor::-webkit-scrollbar { width: 6px; }
  #editor::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.15); border-radius: 3px; }

  /* Status bar */
  #notepad-statusbar {
    height: 24px; min-height: 24px;
    background: #e95420; display: flex; align-items: center; padding: 0 12px;
    font-size: 11px; color: rgba(255,255,255,0.9); gap: 12px; flex-shrink: 0;
  }

  /* Scrollbar global */
  ::-webkit-scrollbar { width: 6px; height: 6px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.15); border-radius: 3px; }
</style>
</head>
<body>
