    </div>
  </div>

  <!-- Notepad Window -->
  <div class="window hidden" id="notepad-window">
    <div class="win-titlebar" data-win="notepad-window">
      <div class="win-dots">
        <div class="win-dot red win-close" data-win="notepad-window"></div>
        <div class="win-dot yellow"></div>
        <div class="win-dot green"></div>
      </div>
