      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
        <path d="M3 7a2 2 0 012-2h4l2 2h8a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2V7z" fill="rgba(255,255,255,0.15)" stroke="rgba(255,255,255,0.8)"/>
      </svg>
      Files
    </button>
    <button class="dock-btn" id="open-notepad" title="Notepad">
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
        <rect x="4" y="2" width="16" height="20" rx="2" fill="rgba(255,255,255,0.15)" stroke="rgba(255,255,255,0.8)"/>
        <line x1="8" y1="8" x2="16" y2="8" stroke="rgba(255,255,255,0.7)"/>
        <line x1="8" y1="12" x2="16" y2="12" stroke="rgba(255,255,255,0.7)"/>
        <line x1="8" y1="16" x2="12" y2="16" stroke="rgba(255,255,255,0.7)"/>
      </svg>
      Notepad
