</div>

<script>
// ── Clock ─────────────────────────────────────────────────────────────
function updateClock() {
  const now = new Date();
  document.getElementById('topbar-time').textContent =
    now.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) +
    '  ' + now.toLocaleDateString([], {weekday:'short', month:'short', day:'numeric'});
}
updateClock();
setInterval(updateClock, 10000);

// ── Filesystem ────────────────────────────────────────────────────────
const FS = {
  '/': { type:'dir', children: ['bin','etc','home','usr','var','tmp','opt'] },
  '/bin': { type:'dir', children: ['bash','ls','cp','mv','rm','cat','echo','grep','find','chmod'] },
  '/etc': { type:'dir', children: ['passwd','hosts','fstab','hostname','resolv.conf','apt','ssh','cron.d'] },
  '/etc/apt': { type:'dir', children: ['sources.list','trusted.gpg'] },
  '/etc/ssh': { type:'dir', children: ['sshd_config','ssh_config','known_hosts'] },
  '/home': { type:'dir', children: ['user'] },
  '/home/user': { type:'dir', children: ['Documents','Downloads','Pictures','Music','Videos','Desktop','.bashrc','.profile'] },
  '/home/user/Documents': { type:'dir', children: ['notes.txt','resume.pdf','project-plan.md','taxes-2025.pdf'] },
  '/home/user/Downloads': { type:'dir', children: ['ubuntu-24.04.iso','package.deb','archive.tar.gz','readme.txt'] },
  '/home/user/Pictures': { type:'dir', children: ['wallpaper.png','screenshot.png','vacation','memes'] },
  '/home/user/Pictures/vacation': { type:'dir', children: ['beach.jpg','sunset.jpg','food.jpg'] },
  '/home/user/Pictures/memes': { type:'dir', children: ['linux_meme.png','coding.gif'] },
  '/home/user/Music': { type:'dir', children: ['playlist.m3u','favorites'] },
  '/home/user/Music/favorites': { type:'dir', children: ['track01.mp3','track02.mp3','track03.flac'] },
  '/home/user/Videos': { type:'dir', children: ['tutorial.mp4','recording.mkv'] },
  '/home/user/Desktop': { type:'dir', children: ['shortcuts.txt'] },
  '/usr': { type:'dir', children: ['bin','lib','local','share','include'] },
  '/usr/bin': { type:'dir', children: ['python3','node','npm','git','vim','nano','curl','wget'] },
  '/usr/lib': { type:'dir', children: ['systemd','python3','x86_64-linux-gnu'] },
  '/usr/local': { type:'dir', children: ['bin','lib','share'] },
  '/usr/share': { type:'dir', children: ['doc','man','icons','fonts'] },
  '/var': { type:'dir', children: ['log','cache','tmp','lib','run'] },
  '/var/log': { type:'dir', children: ['syslog','auth.log','kern.log','dpkg.log','apt'] },
  '/var/cache': { type:'dir', children: ['apt','fontconfig'] },
  '/tmp': { type:'dir', children: ['.X11-unix','tmux-1000'] },
  '/opt': { type:'dir', children: ['google','brave'] },
};

function isDir(path) {
  return FS[path] && FS[path].type === 'dir';
}

function getEntries(path) {
  if (!FS[path] || !FS[path].children) return [];
  return FS[path].children;
}

function joinPath(base, name) {
  if (base === '/') return '/' + name;
  return base + '/' + name;
}

function parentPath(path) {
  if (path === '/') return '/';
  const parts = path.split('/');
  parts.pop();
  return parts.join('/') || '/';
}

// SVG icons
function folderIcon(color='#2d7dd2') {
  return `<svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M3 7a2 2 0 012-2h4l2 2h8a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2V7z" fill="${color}" stroke="${color}" stroke-width="0.5"/>
  </svg>`;
}

function fileIcon(name) {
  const ext = name.split('.').pop().toLowerCase();
  const colors = {
    txt:'#aaa', md:'#6af', pdf:'#e55', iso:'#c8a', deb:'#a8c',
    gz:'#fa8', tar:'#fa8', mp3:'#8fa', flac:'#8fa', mp4:'#f8a',
    mkv:'#f8a', png:'#8cf', jpg:'#8cf', gif:'#8cf', sh:'#8f8',
    conf:'#fc8', log:'#aaa', list:'#aaa',
  };
  const col = colors[ext] || '#8899aa';
  return `<svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M6 2h9l4 4v16a1 1 0 01-1 1H6a1 1 0 01-1-1V3a1 1 0 011-1z" fill="${col}22" stroke="${col}" stroke-width="1.2"/>
    <polyline points="14,2 14,6 18,6" stroke="${col}" stroke-width="1.2" fill="none"/>
    <text x="12" y="16" text-anchor="middle" font-size="5" fill="${col}" font-family="monospace">${ext.toUpperCase().slice(0,4)}</text>
  </svg>`;
}

function hiddenFileIcon() {
  return `<svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M6 2h9l4 4v16a1 1 0 01-1 1H6a1 1 0 01-1-1V3a1 1 0 011-1z" fill="#44445522" stroke="#666" stroke-width="1.2" stroke-dasharray="2 1"/>
  </svg>`;
}

// Files state
let currentPath = '/';
let lastClick = { name: null, time: 0 };

function renderFiles() {
  const content = document.getElementById('files-content');
  document.getElementById('files-path').textContent = currentPath;
  content.innerHTML = '';

  const entries = getEntries(currentPath);
  entries.forEach(name => {
    const fullPath = joinPath(currentPath, name);
    const dir = isDir(fullPath);
    const hidden = name.startsWith('.');

    const item = document.createElement('div');
    item.className = 'fs-item';
    item.dataset.name = name;
    item.dataset.fullpath = fullPath;
    item.dataset.isdir = dir ? '1' : '0';

    let icon;
    if (dir) {
      const folderColors = {
        Documents:'#2d7dd2', Downloads:'#e8a020', Pictures:'#28c840',
        Music:'#9b59b6', Videos:'#e74c3c', Desktop:'#1abc9c',
        home:'#e8a020', usr:'#3498db', bin:'#e74c3c', etc:'#e67e22',
        var:'#8e44ad', tmp:'#7f8c8d', opt:'#2ecc71', lib:'#1abc9c',
        local:'#3498db', share:'#e8a020', log:'#c0392b', cache:'#7f8c8d',
        user:'#f39c12',
      };
      icon = folderIcon(folderColors[name] || '#4a90d9');
    } else if (hidden) {
      icon = hiddenFileIcon();
    } else {
      icon = fileIcon(name);
    }

    item.innerHTML = icon + `<span>${name}</span>`;
    item.addEventListener('click', () => {
      document.querySelectorAll('.fs-item').forEach(i => i.classList.remove('selected'));
      item.classList.add('selected');
      const now = Date.now();
      if (lastClick.name === name && now - lastClick.time < 500 && dir) {
        currentPath = fullPath;
        renderFiles();
      }
      lastClick = { name, time: now };
    });

    content.appendChild(item);
  });
}

document.getElementById('files-up').addEventListener('click', () => {
  currentPath = parentPath(currentPath);
  renderFiles();
});

renderFiles();

// ── Notepad / localStorage ────────────────────────────────────────────
const LS_KEY = 'desktop_notepad_v1';

function loadNotepadState() {
  try {
    const raw = localStorage.getItem(LS_KEY);
    if (raw) return JSON.parse(raw);
  } catch(e) {}
  return { tabs: [{id: 1, name: 'Untitled 1', content: ''}], activeId: 1, nextId: 2 };
}

function saveNotepadState() {
  try {
    localStorage.setItem(LS_KEY, JSON.stringify(notepadState));
  } catch(e) {}
}

let notepadState = loadNotepadState();

function renderTabs() {
  const tabsEl = document.getElementById('tabs');
  tabsEl.innerHTML = '';
  notepadState.tabs.forEach(tab => {
    const el = document.createElement('div');
    el.className = 'tab' + (tab.id === notepadState.activeId ? ' active' : '');
    el.dataset.id = tab.id;
    el.innerHTML = `<span class="tab-name">${escHtml(tab.name)}</span><button class="tab-close" data-id="${tab.id}" title="Close tab">×</button>`;
    el.addEventListener('click', (e) => {
      if (e.target.classList.contains('tab-close')) return;
      switchTab(tab.id);
    });
    tabsEl.appendChild(el);
  });

  // Close buttons
  tabsEl.querySelectorAll('.tab-close').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      closeTab(parseInt(btn.dataset.id));
    });
  });

  // Update editor
  const active = notepadState.tabs.find(t => t.id === notepadState.activeId);
  const editor = document.getElementById('editor');
  if (active) {
    editor.value = active.content;
  } else {
    editor.value = '';
  }
}

function escHtml(s) {
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

function switchTab(id) {
  // Save current content
  const cur = notepadState.tabs.find(t => t.id === notepadState.activeId);
  if (cur) cur.content = document.getElementById('editor').value;
  notepadState.activeId = id;
  saveNotepadState();
  renderTabs();
}

function closeTab(id) {
  if (notepadState.tabs.length === 1) {
    // Reset to empty instead of closing last tab
    notepadState.tabs[0].content = '';
    notepadState.tabs[0].name = 'Untitled 1';
    notepadState.activeId = notepadState.tabs[0].id;
    saveNotepadState();
    renderTabs();
    return;
  }
  const idx = notepadState.tabs.findIndex(t => t.id === id);
  notepadState.tabs.splice(idx, 1);
  if (notepadState.activeId === id) {
    const newIdx = Math.min(idx, notepadState.tabs.length - 1);
    notepadState.activeId = notepadState.tabs[newIdx].id;
  }
  saveNotepadState();
  renderTabs();
}

document.getElementById('new-tab').addEventListener('click', () => {
  // Save current
  const cur = notepadState.tabs.find(t => t.id === notepadState.activeId);
  if (cur) cur.content = document.getElementById('editor').value;

  const id = notepadState.nextId++;
  notepadState.tabs.push({ id, name: `Untitled ${id}`, content: '' });
  notepadState.activeId = id;
  saveNotepadState();
  renderTabs();
  document.getElementById('editor').focus();
});

document.getElementById('editor').addEventListener('input', (e) => {
  const cur = notepadState.tabs.find(t => t.id === notepadState.activeId);
  if (cur) {
    cur.content = e.target.value;
    // Update tab name from first line
    const firstLine = cur.content.split('\n')[0].trim();
    if (firstLine) {
      cur.name = firstLine.length > 20 ? firstLine.slice(0, 20) + '…' : firstLine;
    } else {
      cur.name = `Untitled ${cur.id}`;
    }
    saveNotepadState();
    renderTabs();
  }
});

// Editor cursor position
document.getElementById('editor').addEventListener('keyup', updateEditorPos);
document.getElementById('editor').addEventListener('click', updateEditorPos);
function updateEditorPos() {
  const ed = document.getElementById('editor');
  const text = ed.value.substring(0, ed.selectionStart);
  const lines = text.split('\n');
  const ln = lines.length;
  const col = lines[lines.length - 1].length + 1;
  document.getElementById('editor-pos').textContent = `Ln ${ln}, Col ${col}`;
}

renderTabs();

// ── Window Management ─────────────────────────────────────────────────
function showWindow(id) {
  const win = document.getElementById(id);
  win.classList.remove('hidden');
  bringToFront(win);
}

function hideWindow(id) {
  document.getElementById(id).classList.add('hidden');
}

function bringToFront(win) {
  let maxZ = 100;
  document.querySelectorAll('.window').forEach(w => {
    const z = parseInt(w.style.zIndex) || 100;
    if (z > maxZ) maxZ = z;
  });
  win.style.zIndex = maxZ + 1;
}

// Launcher buttons
document.getElementById('open-files').addEventListener('click', () => showWindow('files-window'));
document.getElementById('open-notepad').addEventListener('click', () => {
  showWindow('notepad-window');
  renderTabs();
  setTimeout(() => document.getElementById('editor').focus(), 50);
});

// Close buttons
document.querySelectorAll('.win-close').forEach(btn => {
  btn.addEventListener('click', () => {
    hideWindow(btn.dataset.win);
  });
});

// Click on window brings to front
document.querySelectorAll('.window').forEach(win => {
  win.addEventListener('mousedown', () => bringToFront(win));
});

// ── Dragging ──────────────────────────────────────────────────────────
let drag = null;

document.querySelectorAll('.win-titlebar').forEach(tb => {
  tb.addEventListener('mousedown', (e) => {
    if (e.target.classList.contains('win-dot')) return;
    const win = document.getElementById(tb.dataset.win);
    const rect = win.getBoundingClientRect();
    drag = {
      win,
      dx: e.clientX - rect.left,
      dy: e.clientY - rect.top,
    };
    bringToFront(win);
    e.preventDefault();
  });
});

document.addEventListener('mousemove', (e) => {
  if (!drag) return;
  const x = e.clientX - drag.dx;
  const y = e.clientY - drag.dy;
  drag.win.style.left = Math.max(0, x) + 'px';
  drag.win.style.top = Math.max(28, y) + 'px';
  drag.win.style.right = 'auto';
  drag.win.style.bottom = 'auto';
});

document.addEventListener('mouseup', () => { drag = null; });

// ── Initial state ─────────────────────────────────────────────────────
// Files window shown by default, notepad hidden
// (files-window is already visible, notepad-window has class "hidden")
</script>
